mapper.select:
select su.user_id,su.name,su.phone,su.gender,su.age,su.user_number,su.verified,su.dept_id,sd.name as deptName
from cm_customer su
left join sys_dept sd on su.dept_id = sd.dept_id
where su.del_flag = '0' and su.role_id = 2 and su.verified = '2'

	and su.merchant_id = #{vo.merchantId}


	and su.name like concat('%', #{vo.name}, '%')


	and su.verified = #{vo.verified}


	and su.dept_id = #{vo.deptId}

order by su.update_time desc
